const res = $input.first().json;
const row = res.body !== undefined ? res.body : res;
const results = Array.isArray(row.results) ? row.results : [];
function rt(prop) {
  if (!prop) return '';
  if (prop.type === 'title') return (prop.title || []).map((t) => t.plain_text).join('');
  if (prop.type === 'rich_text') return (prop.rich_text || []).map((t) => t.plain_text).join('');
  return '';
}
if (!results.length) {
  return [{ json: { _queueEmpty: true, _trigger: 'schedule' } }];
}
const page = results[0];
const props = page.properties || {};
const topicField = props.Topic || props.topic;
const topic = rt(topicField).trim() || 'Forensic scheduling, HVDC, and owner-side project controls';
return [{
  json: {
    mode: 'post',
    topic,
    post_id: '',
    comment_text: '',
    comment_author: 'LinkedIn member',
    scheduled_at: '',
    _trigger: 'schedule',
    _notionQueuePageId: page.id,
    _queueEmpty: false,
  },
}];

const j = $input.first().json;
const body = (j.body !== undefined && j.body !== null && typeof j.body === 'object' && !Array.isArray(j.body)) ? j.body : j;
const trigger = j.body !== undefined ? 'webhook' : 'schedule';
const mode = String(body.mode || 'post').toLowerCase();
const topic = String(body.topic || 'Forensic scheduling, HVDC, and owner-side project controls').trim();
const post_id = String(body.post_id || '').trim();
const comment_text = String(body.comment_text || '').trim();
const comment_author = String(body.comment_author || 'LinkedIn member').trim();
const scheduled_at = String(body.scheduled_at || '').trim();
return [{ json: { mode, topic, post_id, comment_text, comment_author, scheduled_at, _trigger: trigger } }];

const j = $input.first().json;
if (j.mode === 'reply') {
  if (!j.post_id || !j.comment_text) {
    return [{ json: { ...j, _valid: false, _error: 'reply mode requires post_id and comment_text' } }];
  }
}
return [{ json: { ...j, _valid: true } }];

const v = $('Validate Mode Inputs').first().json;
const system = "You are Michael Craig, founder of Exsto Cura Consilium (exstocura.com), Houston, TX. You are a practitioner, not a marketer. 25+ years in project controls: HVDC transmission, offshore wind, energy infrastructure. You specialize in forensic scheduling, AACE-aligned Time Impact Analysis (TRIAGE-IMPACT™), Primavera P6, and change order development. Your anchor proof of concept is CO-015, a $27M settlement on the Champlain Hudson Power Express (CHPE) where AI-enabled schedule forensics found causation chains manual analysis had missed. You are a SmartPM consulting partner. LinkedIn voice: direct, specific, occasionally provocative. No buzzwords. No em dashes. No bullet points in posts. You write like a peer talking to peers. Return only the final post text.";
const user = `Write a high-performing LinkedIn post about this topic or angle:

${v.topic}

Rules:
- 150-250 words
- First line must be bold on LinkedIn: wrap it in **double asterisks**. Never open with I'm excited to share or similar filler
- Include one concrete data point or example from energy infrastructure or project controls
- End with a single CTA or one sharp question to drive comments
- Use 2-4 line breaks for scannability
- End with 3-5 relevant hashtags on the last line
- No em dashes. No bullet points

Return post text only, ready to publish.`;
return [{ json: { ...v, anthropic_system: system, anthropic_user: user, action: 'create_post' } }];

