const v = $('Validate Mode Inputs').first().json;
const action = v.mode === 'reply' ? 'reply_comment' : 'create_post';
const http = $input.first().json;
const statusCode = Number(http.statusCode ?? http.status_code ?? 0);
const row = http.body !== undefined ? http.body : http;
const block = (row.content || []).find((c) => c.type === 'text');
const text = (block && block.text) ? String(block.text).trim() : '';
let claude_ok = true;
let claude_error_detail = '';
if (statusCode < 200 || statusCode >= 300) {
  claude_ok = false;
  claude_error_detail = 'HTTP ' + statusCode + ' ' + (typeof row === 'string' ? row : JSON.stringify(row)).slice(0, 400);
} else if (row.type === 'error') {
  claude_ok = false;
  claude_error_detail = JSON.stringify(row.error || row).slice(0, 400);
} else if (!text) {
  claude_ok = false;
  claude_error_detail = 'empty_completion';
}
return [{ json: { ...v, action, generated_content: text, claude_ok, claude_error_detail, claude_statusCode: statusCode } }];

const v = $('Validate Mode Inputs').first().json;
const system = "You are Michael Craig, founder of Exsto Cura Consilium. You reply on LinkedIn as a senior project controls practitioner (HVDC, offshore wind, forensic scheduling, AACE-aligned TIA, P6, change orders). CO-015 / CHPE and SmartPM partnership are fair context when relevant. Sound human, not AI-generated. Never use phrases like "Great point!" or "Thanks for sharing." No sycophancy. Return only the reply text.";
const user = `Reply to this LinkedIn comment on one of your posts.

Comment author: ${v.comment_author}
Their comment: ${v.comment_text}
Thread context (what your original post was about): ${v.topic}

Rules:
- 1-3 sentences maximum
- Add a specific insight, pushback, or follow-up question
- No hashtags unless truly necessary (usually skip)

Return reply text only.`;
return [{ json: { ...v, anthropic_system: system, anthropic_user: user, action: 'reply_comment' } }];

