const v = $('Validate Mode Inputs').first().json;
const qg = $('Quality Gate (>= 50 chars)').first().json;
const iso = String(v.scheduled_at || '').trim();
let shareMode = 'shareNow';
let dueAt = '';
if (iso.length > 8) {
  shareMode = 'customScheduled';
  dueAt = iso.includes('T') ? iso : new Date(iso).toISOString();
}
return [{ json: {
  ...qg,
  _buffer_share_mode: shareMode,
  _buffer_due_at: dueAt || new Date().toISOString(),
  _notion_queue_page_id: String(v._notionQueuePageId || ''),
  _trigger: v._trigger,
}}];

const qg = $('Quality Gate (>= 50 chars)').first().json;
const v = $('Validate Mode Inputs').first().json;
const item = $input.first();
const inp = item.json || {};
let statusCode = 200;
let detail = '';
if (item.error) {
  const e = item.error;
  statusCode = Number(e.httpCode || e.statusCode || e.status || 400);
  if (!statusCode || statusCode < 400) statusCode = 400;
  detail = JSON.stringify(e).slice(0, 1500);
} else {
  const j = inp;
  detail = typeof j === 'string' ? j : JSON.stringify(j).slice(0, 1500);
}
return [{ json: {
  _trigger: v._trigger,
  action: qg.action,
  topic: qg.topic,
  post_id: qg.post_id,
  generated_content: qg.generated_content,
  statusCode,
  buffer_body: detail,
  _notion_queue_page_id: String(v._notionQueuePageId || ''),
}}];

const j = $input.first().json;
const sc = Number(j.statusCode);
let bucket = 'success';
if (sc >= 400 && sc < 500) bucket = 'buffer_fail';
else if (sc >= 500) bucket = 'buffer_fail';
else if (sc < 200 || sc >= 300) bucket = 'buffer_fail';
return [{ json: { ...j, _bucket: bucket } }];

